Scripts.Script:
        // 

    var gdelayShow = 10000,
        gdelayCheck = 200,
        LaunchChNum = -1;

        var channelOrig, channelNew;

function init() {
    channelOrig = getProperty("FsDS", "channel");
    if (channelOrig == "9999") {
        invokeAction(null, "exit");
        return false
    }
    checkChannelW()
}

function loadApp() {
    if (checkChannelW()) {
        invokeAction("","InitialDelay");

    }
}

function checkChannelW() {
    channelNew = getProperty("FsDS", "channel");
    if (channelNew == "9999") {
        invokeAction("", "Kill");
        return false
    }
    if (channelNew != channelOrig) {
        invokeAction("", "Kill");
        return false
    }
    setTimeout("checkChannelW()", 1000);
    return true
}

   function checkRez() {
    //setProperty("Msg", "visible", "false");
    var w = getProperty("SystemDS", "width")
    alert("width: " + w);
    if (w == "640") {
        setProperty("GenericTrigger", "width", 640);
       //setProperty("Msg", "width", 640);
    }
}

function checkChannel() {

          invokeAction("","RefreshFS");
                        var b = getProperty("FsDS", "channel"),
                            c = LaunchChNum;

                    alert("b -" + b + "c - " + c );
                    if(c == "-1")
                    {
                      alert("lcn set to " + b);
                      LaunchChNum = b;
                    }
                    else if( c != b)
                    {
                      alert("diff channel");
                      invokeAction("", "Kill");
                    }
                    else
                      alert("still on launch channel");
                }

  function handleKey() {

  var a = window.readContext("keyname");
    window.writeContext("handled", false);
    if (a != "mute" && a != "volumeup" && a != "volumedown" && a != "play" && a != "pause" && a != "record" && a != "rec" && a != "skipfwd" && a != "skipback" && a != "rwd" && a != "ffwd" && a != "stop") {
        alert("handle key action");
        invokeAction("", "Kill");
    }
   }


function checkMsgToggle() {
    alert("checkMesgToggle");
    var gg = '/root/@active';
    var hh = getProperty("HsiaCheckDS", gg);
    if(hh == 'off')
    {
      invokeAction("", "Kill");
    }

    //chk msg count
    var pp = getProperty("HsiaCheckDS", '//msgs/msg');
    alert("pp " + pp);
    if(pp == null)
    {
      invokeAction("", "Kill");
    }

     var gp = "|"+ getProperty("FsDS", "channel") + "|";
     alert("gp" + gp);
    var ga ="//msgs/msg[contains(@tchs,'"+gp+"')]";
    alert("ga - " + ga);
    var qq = getProperty("HsiaCheckDS", ga);
    //alert("qq - " + qq);
    if(qq != null && qq.length > 0)
    {
      alert("here");
       var g = ga+'/@t';
       var h = getProperty("HsiaCheckDS", g);
       var p = ga + '/@hash';
       var k = ga + '/@sd';
       gdelayShow = getProperty("HsiaCheckDS", k);
       alert("gdelayShow - " + gdelayShow);
       var j = ga + '/@vt';
       gdelayCheck = getProperty("HsiaCheckDS", j);
       alert("gdelayCheck - " + gdelayCheck);
       alert("h - " + h);
       if (h == 'on') {
           checkChannel();
           var showMsg = false;
           var q = getProperty("HsiaCheckDS", p); //akamai hash
           alert("q - " + q);
           var r = getProperty("MsgHash", "text");
           if((r == "-1") || (r != q)) //no previous hash
            {
              setProperty("MsgHash", "text", q);
              showMsg = true;
           }
           else if(r == q)
            {
              showMsg = false;
            }
           if(showMsg)
           {
                var n =  ga +'/text()';
                var m = getProperty("HsiaCheckDS", n);
                alert("m - " + m);
                setProperty("Msg", "text", m);
                invokeAction("", "ShowMsg_Delayed");
                setTimeout("hideMsg()", gdelayShow);
                 //invokeAction("", "HideMsg_Delayed");
          }
          else
            invokeAction("", "HideMsg");
        } else //kill when Toggle is OFF
           invokeAction("", "HideMsg");

    }
    else
     invokeAction("", "HideMsg");

}

function hideMsg()
{
  invokeAction("", "HideMsg");
}

function checkMsgDelayed()
{
    checkChannel();
    invokeAction("", "ShowMsg");
    setTimeout("validateChannel()", gdelayCheck);
    //invokeAction("", "CheckChannel_Delayed");
}

function validateChannel()
{

  checkChannel();
  setTimeout("validateChannel()", gdelayCheck);
  //invokeAction("", "CheckChannel_Delayed");
}

